import React, { useState, useEffect, useRef } from "react";
import { NavLink, useNavigate } from "react-router-dom";
import "./Header.css";

export default function Header() {
  const [searchOpen, setSearchOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const [menuOpen, setMenuOpen] = useState(false);

  const searchRef = useRef(null);
  const navRef = useRef(null);
  const menuButtonRef = useRef(null);
  const navigate = useNavigate(); // 🔹 დაემატა

  useEffect(() => {
    const handleClickOutsideSearch = (e) => {
      if (searchRef.current && !searchRef.current.contains(e.target)) {
        setSearchOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutsideSearch);
    return () =>
      document.removeEventListener("mousedown", handleClickOutsideSearch);
  }, []);

  const handleSearchSubmit = (e) => {
    e.preventDefault();
    if (!searchQuery.trim()) return;

    navigate(`/articles?q=${encodeURIComponent(searchQuery)}`); // 🔹 რეალური ძებნა
    setSearchOpen(false);
  };

  return (
    <header className="header">
      <div className="logo">
        <NavLink to="/">
          <img src="/mb.png" alt="MBTI Logo" />
        </NavLink>
      </div>

      <nav ref={navRef} className={`nav ${menuOpen ? "open" : ""}`}>
        <ul>
          <li><NavLink to="/" end>მთავარი</NavLink></li>
          <li><NavLink to="/mbti-dimensions">MBTI განზომილებები</NavLink></li>
          <li><NavLink to="/articles">მიმოხილვები</NavLink></li>
          <li><NavLink to="/start-test">დაიწყე ტესტი</NavLink></li>
          <li><NavLink to="/register">Sign in</NavLink></li>
        </ul>
      </nav>

      <div className="header-actions" ref={searchRef}>
        <button
          className="search-toggle"
          onClick={() => setSearchOpen(p => !p)}
        >
          <img src="/search.png" alt="ძებნა" className="search-icon" />
        </button>

        {searchOpen && (
          <form className="search-form" onSubmit={handleSearchSubmit}>
            <input
              type="text"
              placeholder="ძებნა საიტზე..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              autoFocus
            />
            <button type="submit">ძიება</button>
          </form>
        )}
      </div>
    </header>
  );
}
